          "type": "string",
          "description": "訂單編號，例如 A123456789",
          "pattern": "^[A-Z]\\d{9}$"
        }
      },
      "required": [
        "order_id"
      ],
      "additionalProperties": false
    }
  },
  {
    "name": "get_order_items",
    "description": "查詢訂單的商品明細（品名、數量、單價、小計、總額）。",
    "parameters": {
      "type": "object",
      "properties": {
        "order_id": {
          "type": "string",
          "description": "訂單編號，例如 A123456789",
