          ]
        },
        "summary": {
          "type": "string",
          "description": "案件摘要（簡述使用者的問題或需求）"
        },
        "order_id": {
          "type": "string",
          "description": "相關訂單編號（可選）",
          "pattern": "^[A-Z]\\d{9}$"
        }
      },
      "required": [
        "topic",
        "summary"
      ],
      "additionalProperties": false
    }
  }
